        "address": "-",
        "contact": "Allegra Films:\nmayca@allegrafilms.com\n+34 629 91 61 87\nhttps://www.allegrafilms.com\n\nNocturna Pictures:\nlaurarubirola@gmail.com\n+34 629 83 00 72\nhttp://nocturnapictures.com/",
